// PATCH: Cover recurring-item matching when identical criteria are shared.

func TestRecurringHasTransactionDoesNotFallbackMatchDifferentRecurringID(t *testing.T) {
	start := recurringTestDate("2026-05-01")
	end := recurringTestDate("2026-05-31")
	txs := []localTransaction{
		recurringTestTx("tx-a", "Streaming", 15.99, "2026-05-03", "recurring-a"),
	}

	found, lastSeen := recurringHasTransaction(txs, "recurring-b", "Streaming", 15.99, start, end)
	if found {
		t.Fatalf("recurringHasTransaction() found transaction linked to a different recurring item, lastSeen %q", lastSeen)
	}
	if lastSeen != "" {
		t.Fatalf("lastSeen = %q, want empty string", lastSeen)
	}
}

func TestRecurringHasTransactionFallbackMatchesUnlinkedTransaction(t *testing.T) {
	start := recurringTestDate("2026-05-01")
	end := recurringTestDate("2026-05-31")
	txs := []localTransaction{
		recurringTestTx("tx-unlinked", "Streaming", 15.99, "2026-05-03", ""),
	}

	found, dateString := recurringHasTransaction(txs, "recurring-a", "Streaming", 15.99, start, end)
	if !found {
		t.Fatalf("recurringHasTransaction() found = false, want true")
	}
	if dateString != "2026-05-03" {
		t.Fatalf("dateString = %q, want 2026-05-03", dateString)
	}
}

func TestRecurringHasTransactionMatchesExactRecurringID(t *testing.T) {
	start := recurringTestDate("2026-05-01")
	end := recurringTestDate("2026-05-31")
	txs := []localTransaction{
		recurringTestTx("tx-a", "Streaming", 17.99, "2026-05-03", "recurring-a"),
	}

	found, dateString := recurringHasTransaction(txs, "recurring-a", "Streaming", 15.99, start, end)
	if !found {
		t.Fatalf("recurringHasTransaction() found = false, want true")
	}
	if dateString != "2026-05-03" {
		t.Fatalf("dateString = %q, want 2026-05-03", dateString)
	}
}

func recurringTestTx(id, payee string, amount float64, dateString, recurringID string) localTransaction {
	date := recurringTestDate(dateString)
	return localTransaction{
		ID:              id,
		Payee:           payee,
		PayeeNormalized: normalizeLocalPayee(payee),
		Amount:          amount,
		Date:            date,
		DateString:      dateString,
		RecurringID:     recurringID,
	}
}

func recurringTestDate(dateString string) time.Time {
	date, err := time.Parse("2006-01-02", dateString)
	if err != nil {
		panic(err)
	}
	return date
}
